CREATE TABLE "jfy_gift" (
    "id" serial NOT NULL,
    "gift_name" varchar(32) NOT NULL,
    "at_least_recharge_count" int NOT NULL DEFAULT 1,
    "comments" jsonb NOT NULL,
    "content" text NOT NULL,
    "cost_price" numeric(10,2) DEFAULT NULL,
    "cover" varchar(255) NOT NULL DEFAULT '',
    "covers" jsonb NOT NULL,
    "description" varchar(62) NOT NULL DEFAULT '',
    "express_type" jsonb NOT NULL,
    "gift_type" int NOT NULL,
    "has_props" boolean NOT NULL DEFAULT false,
    "is_limit_sell" boolean NOT NULL DEFAULT false,
    "limit_customer_tags" jsonb NOT NULL,
    "limit_sell_custom" boolean NOT NULL DEFAULT false,
    "limit_sell_cycle" varchar(32) NOT NULL DEFAULT '',
    "limit_sell_cycle_count" int NOT NULL DEFAULT 0,
    "limit_sell_type" smallint NOT NULL DEFAULT 0,
    "market_price" numeric(10,2) NOT NULL,
    "out_sn" varchar(255) NOT NULL DEFAULT '',
    "props" jsonb NOT NULL,
    "skus" jsonb NOT NULL,
    "score_price" numeric(10,2) NOT NULL,
    "stock" int NOT NULL DEFAULT 0,
    "create_at" timestamp NOT NULL,
    "store_id" int NOT NULL,
    "status" int DEFAULT 1,
    "view_count" int NOT NULL DEFAULT 0,
    "sell_count" int DEFAULT 0,
    PRIMARY KEY ("id")
);

